import{_ as i,a as o,b as u,c as n,d as s}from"./TestNavigationButtons-4fd3a533.js";import{_ as a}from"./QuestionTemp4.vue_vue_type_script_setup_true_lang-881cec57.js";import{S as c}from"./SeihoTestLayout-60cc1332.js";import{o as y,c as v,w as r,b as p,a as e}from"./app-2d659ee4.js";import"./AdSenseUnit.vue_vue_type_script_setup_true_lang-c373695c.js";const k={class:"bg-gray-100 text-gray-800 py-10"},b={class:"max-w-4xl mx-auto mt-4 space-y-2"},t="生命保険計理",l="2023年度 フォームA",w={__name:"Keiri2023a",setup(T){return(m,f)=>(y(),v(c,{title:t},{default:r(()=>[p("section",k,[e(i,{title:t,description:l}),p("div",b,[e(a,{questionNumber:1,title:t,subject:l,contents:[{answer:"5,425",questionTitle:"複利計算",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"複利では、元金に利息が組み込まれながら増えていく。まず6か月後の元利合計を求め、そこから元金を差し引いて利息を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 利率)<sup>運用期間</sup>","利息 = 元利合計 − 元金"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：500,000円","月利：0.18％ = 0.0018","運用期間：6か月"]},{type:"text",value:"① 元利合計"},{type:"formulaBlock",value:["= 500,000円 × (1 + 0.0018)<sup>6</sup>","= 500,000円 × 1.010849","= 505,424.5円"]},{type:"text",value:"② 利息"},{type:"formulaBlock",value:["= 505,424.5円 − 500,000円","= 5,424.5円"]},{type:"result",value:"▶ 答え 5,425円（円未満四捨五入）"}]},{answer:"522,926",questionTitle:"複利計算（半年複利）",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年利1.5％で半年複利の場合、半年ごとに0.75％ずつ増える。3年間では半年が6回あるため、半年利率で6回複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["元利合計 = 元金 × (1 + 期間利率)<sup>複利回数</sup>"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["元金：500,000円","年利：1.5％","半年利率：= 1.5％ ÷ 2 = 0.75％ = 0.0075","複利回数：= 3年 × 年2回 = 6回"]},{type:"formulaBlock",value:["元利合計","= 500,000円 × (1 + 0.0075)<sup>6</sup>","= 500,000円 × 1.0458522","= 522,926.1円"]},{type:"result",value:"▶ 答え 522,926円（円未満四捨五入）"}]},{answer:"1.51",questionTitle:"実利率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"実利率とは、1年間に実際どれだけ増えるかを示す利率。名称利率が年率でも、年に複数回利息が付く場合は、その回数分だけ複利計算する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["実利率 =（ 1 + 名称利率 ÷ 転化回数）<sup>転化回数</sup> - 1"]},{type:"note",value:"転化回数：1年間に利息を元金に繰り入れる回数"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 1回あたりの利率"},{type:"formulaBlock",value:["= 0.015 ÷ 4","= 0.00375"]},{type:"text",value:"② 実利率"},{type:"formulaBlock",value:["= (1 + 0.00375)<sup>4</sup> − 1","= 1.015084 − 1","= 0.015084 = 1.5084％"]},{type:"result",value:"▶ 答え 1.51％（小数第3位を四捨五入）"}]},{answer:"1.23",questionTitle:"年平均利回り",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"まず、5年間の複利でどれだけ増えたか（総利回り）を求める。その後、それを5年で平均したものが年平均利回り。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["総利回り = (1 + 複利利率)<sup>期間</sup> − 1","年平均利回り = 総利回り ÷ 期間"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["複利利率：1.2％ = 0.012","投資期間：5年"]},{type:"text",value:"① 総利回り"},{type:"formulaBlock",value:["= (1 + 0.012)<sup>5</sup> − 1","= 1.0617 − 1","= 0.0617"]},{type:"text",value:"② 年平均利回り"},{type:"formulaBlock",value:["= 0.0617 ÷ 5","= 0.01234 = 1.234％"]},{type:"result",value:"▶ 答え 1.23％（小数第3位を四捨五入）"}]},{answer:"2,710,245円",questionTitle:"必要資金（現在価値）",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"毎年始（期始）に40万円を7年間支払うので、各年の支払額をそれぞれ現在価値に割り引き、その合計を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["現在価値 = 将来の金額 × (1 ÷ (1 + 利率))<sup>年数</sup>","必要資金 = 各年の支払額の現在価値の合計"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["毎年の支払額：400,000円（年始）","期間：7年間","年利率：1.1％ = 0.011"]},{type:"text",value:"① 各年の支払額の現在価値"},{type:"formulaBlock",value:["初年度：400,000円","1年後：400,000 × (1 ÷ 1.011) = 395,648円","2年後：400,000 × (1 ÷ 1.011)<sup>2</sup> = 391,343.2円","3年後：400,000 × (1 ÷ 1.011)<sup>3</sup> = 387,085.2円","4年後：400,000 × (1 ÷ 1.011)<sup>4</sup> = 382,873.6円","5年後：400,000 × (1 ÷ 1.011)<sup>5</sup> = 378,707.6円","6年後：400,000 × (1 ÷ 1.011)<sup>6</sup> = 374,587.2円"]},{type:"text",value:"② 合計"},{type:"formulaBlock",value:["現在価値の合計","= 400,000 + 395,648 + 391,343.2 + 387,085.2 + 382,873.6 + 378,707.6 + 374,587.2","= 2,710,244.764…円"]},{type:"result",value:"▶ 答え 2,710,245円（円未満四捨五入）"}]}],labels:["カ","ク","ウ","ア","コ"]}),e(a,{questionNumber:6,title:t,subject:l,contents:[{answer:"0.98530",questionTitle:"生存率",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"生存率とは、「ある年齢の人が、次の年齢まで生き残る割合」のこと。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["生存率 = 期末の生存数 ÷ 期初の生存数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["生存率（48歳 → 55歳）","= 55歳の生存数 ÷ 48歳の生存数","= 96,441 ÷ 97,880 = 0.985298"]},{type:"result",value:"▶ 答え 0.98530（小数第6位を四捨五入）"}]},{answer:"98,455",questionTitle:"生存数",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"「3年後に何人残るか」は、今の人数に“3年間生き残る割合（生存率）を掛けることで求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formula",value:"N年後の生存者数 = 基準年齢の人数 × 生存率（問１参照）"},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"3年後の生存者数"},{type:"formulaBlock",value:["基準年齢（65歳）の人数 × 生存率（65歳 → 68歳）","= 100,000 × 91,616 ÷ 93,054 = 98454.6"]},{type:"result",value:"▶ 答え 98,455（小数第1位を四捨五入）"}]},{answer:"1.02",questionTitle:"平均余命",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"平均余命とは、その年齢の全員がこれから生きる年数を全部足して、今の人数で割ったもの。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["延べ生存年数 = 死亡数 × 平均生存年数","平均余命 = 延べ生存年数の合計 ÷ 生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 各年齢の延べ生存年数"},{type:"note",value:"各年齢の死亡者は、その年齢内で平均<strong>0.5年</strong>生存したとみなして計算する。"},{type:"formulaBlock",value:["109歳：25.888 × 0.5 = 12.94","110歳：10.1008 × 1.5 = 15.15","111歳：3.4515 × 2.5 = 8.63","112歳：1.0162 × 3.5 = 3.56","113歳：0.3155 × 4.5 = 1.42"]},{type:"text",value:"② 109歳～113歳の延べ生存年数の合計"},{type:"note",value:"109歳以上の全員が、合計で何年分生きたかを合算する。"},{type:"formulaBlock",value:["12.94 + 15.15 + 8.63 + 3.56 + 1.42 = 41.7"]},{type:"text",value:"③ 109歳の平均余命"},{type:"formulaBlock",value:["109歳～113歳の延べ生存年数の合計 ÷ 109歳の生存者数","= 41.7 ÷ 40.772","= 1.022"]},{type:"result",value:"▶ 答え 1.02（小数第3位を四捨五入）"}]},{answer:"955,236",questionTitle:"保険金総額の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"1年定期保険では、1年間に死亡した人に保険金を支払う。したがって、まず死亡者全員に支払う保険金の合計額を出し、支払い時点を年央（期央）とみなして、期央払現価率で割り引いて現価を求める。"},{type:"note",value:"※期央払現価率とは、年の真ん中で支払われると仮定したときの割引係数。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["合計保険金額 = 保険金 × 死亡数","現価 = 合計保険金額 × 期央払現価率（利率1.0%）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 合計保険金額"},{type:"formulaBlock",value:["保険金（500万円） × 死亡数（50歳）","= 5,000千円 × 192人","= 960,000千円"]},{type:"text",value:"② 現価（年央払）"},{type:"formulaBlock",value:["合計保険金額 × 期央払現価率（利率1.0%）","= 960,000千円 × 0.995037","= 955,235.52千円"]},{type:"result",value:"▶ 答え：955,236千円（千円未満四捨五入）"}]},{answer:"9,790",questionTitle:"純保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"純保険料は、必要な保険金総額の現価を、加入者全員で負担する額。したがって、必要な現価を年始生存者数で割る。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["純保険料 = 必要な現価 ÷ 年始生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["純保険料","= 必要な現価（問９の解） ÷ 50歳の年始生存者数","= 955,236千円 ÷ 97,539人","= 9,793円"]},{type:"result",value:"▶ 答え 9,790円（10円未満四捨五入）"}]}],labels:["ア","キ","ウ","コ","カ"]}),e(o,{questionNumber:3,questionTitle:"死亡表の種類",title:t,subject:l,contents:["経験生命表","完全生命表","総合表","選択効果","年齢別"],labels:["ウ","ア","キ","カ","コ"]}),e(o,{questionNumber:4,questionTitle:"払済保険",title:t,subject:l,contents:["解約返戻金","残存","そのときの被保険者の到達年齢","新契約費","同じ"],labels:["ウ","キ","ケ","ク","イ"]}),e(a,{questionNumber:21,title:t,subject:l,contents:[{answer:"3,335,427千円",questionTitle:"死亡保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"保険期間（40〜44歳）の各年齢で死亡した場合、死亡保険金が支払われる。支払いは年央（期央）と仮定されるため、各年齢の「死亡保険金 × 死亡数」を期央払現価率で割り引き、現価を合計する。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["各年齢の死亡保険金現価 = 死亡保険金 × 死亡数 × 期央払現価率","死亡保険金現価の合計 = 各年齢の死亡保険金現価の合計"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["死亡保険金：700万円 = 7,000千円","保険期間：5年（40〜44歳）","支払い：年央（期央）と仮定"]},{type:"text",value:"① 各年齢の死亡保険金現価"},{type:"formulaBlock",value:["40歳：7,000千円 × 87 × 0.995037 = 605,978千円","41歳：7,000千円 × 92 × 0.985185 = 634,459千円","42歳：7,000千円 × 98 × 0.975431 = 669,146千円","43歳：7,000千円 × 102 × 0.965773 = 689,562千円","44歳：7,000千円 × 110 × 0.956211 = 736,282千円"]},{type:"text",value:"② 合計"},{type:"formulaBlock",value:["死亡保険金現価の合計","= 605,978 + 634,459 + 669,146 + 689,562 + 736,282","= 3,335,427千円"]},{type:"result",value:"▶ 答え 3,335,427千円"}]},{answer:"654,563,889千円",questionTitle:"満期保険金の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"満期保険金は、保険期間満了時（5年後）に生存している人に支払われる。したがって、まず 5年後の生存者数 × 保険金額 で将来の支払総額を求め、それを 期末払現価率 で割り引いて現価を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["満期保険金の現価 = 5年後の生存者数 × 保険金額 × 期末払現価率（5年）"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：700万円 = 7,000千円","5年後（45歳）の生存数：98,279人","5年の期末払現価率：0.951466"]},{type:"formulaBlock",value:["満期保険金の現価","= 98,279 × 7,000 × 0.951466","= 654,563,889.098千円"]},{type:"result",value:"▶ 答え 654,563,889千円（千円未満四捨五入）"}]},{answer:"17,284,400千円",questionTitle:"予定事業費の現価",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"予定事業費が「保険金1000円につき25円」と与えられているので、まず 1人あたりの予定事業費を求める。その後、加入時（40歳）の生存者数を掛けて、全体の予定事業費（現価）を求める。"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["1人あたりの予定事業費 = 保険金額 ×（25 ÷ 1000）","予定事業費の現価（合計） = 1人あたりの予定事業費 × 加入時の生存者数"]},{type:"blockTitle",value:"■ 計算方法"},{type:"formulaBlock",value:["保険金額：700万円 = 7,000千円","予定事業費：保険金1000円につき25円 = 25 ÷ 1000","40歳の生存数：98,768人"]},{type:"text",value:"① 1人あたりの予定事業費"},{type:"formulaBlock",value:["= 7,000千円 ×（25 ÷ 1000）","= 7,000 × 0.025","= 175千円"]},{type:"text",value:"② 予定事業費の現価（合計）"},{type:"formulaBlock",value:["= 175千円 × 98,768人","= 17,284,400千円"]},{type:"result",value:"▶ 答え 17,284,400千円（千円未満四捨五入）"}]},{answer:"1,397,130円",questionTitle:"養老保険の年払営業保険料",explanation:[{type:"blockTitle",value:"■ 解答のポイント"},{type:"text",value:"年払営業保険料 P は、収支相当の原則（収入現価=支出現価）で求める。"},{type:"text",value:"収入現価：各年齢で生存している人が払う保険料 P を、期始払として現価に直して合計する"},{type:"text",value:"支出現価：死亡保険金・満期保険金・予定事業費の現価を合計する（問21〜23の結果）"},{type:"blockTitle",value:"■ 使用する公式"},{type:"formulaBlock",value:["収支相当の原則：収入現価 = 支出現価","各年齢の収入現価（期始払） = 生存数 × P × 期始払現価率","支出現価 = 死亡保険金現価 + 満期保険金現価 + 予定事業費現価"]},{type:"blockTitle",value:"■ 計算方法"},{type:"text",value:"① 収入現価（40〜44歳、期始払）"},{type:"formulaBlock",value:["40歳：P × 98,768 × 1.000000 = 98,768P","41歳：P × 98,681 × 0.990099 = 97,704P","42歳：P × 98,590 × 0.980296 = 96,647P","43歳：P × 98,492 × 0.970590 = 95,595P","44歳：P × 98,390 × 0.960980 = 94,551P"]},{type:"formulaBlock",value:["収入現価の合計","= 98,768P + 97,704P + 96,647P + 95,595P + 94,551P","= 483,265P"]},{type:"text",value:"② 支出現価（問21〜23より）"},{type:"formulaBlock",value:["死亡保険金の現価（問21）= 3,335,427千円","満期保険金の現価（問22）= 654,563,889千円","予定事業費の現価（問23）= 17,284,400千円"]},{type:"formulaBlock",value:["支出現価","= 3,335,427 + 654,563,889 + 17,284,400","= 675,183,716千円 = 675,183,716,000円"]},{type:"text",value:"③ 収支相当の原則より P を求める"},{type:"formulaBlock",value:["収入現価 = 支出現価 より","483,265P = 675,183,716,000円","P = 675,183,716,000円 ÷ 483,265","P = 1,397,129.4…円"]},{type:"result",value:"▶ 答え 1,397,130円（10円未満四捨五入）"}]}],labels:["ウ","ア","ウ","イ"]}),e(u,{questionNumber:25,title:t,subject:l,questionTitle:"契約者配当金の分配・支払方法",contents:["年払保険料 → 一時払保険料","その年度の保険料にまとめて充当 → 払込回数に等分し、毎回の保険料に充当","正しい"]},null,8,["contents"]),e(u,{questionNumber:26,title:t,subject:l,questionTitle:"営業保険料",contents:["3方式 → 4方式（1契約について予定事業費を一定額とする方式も含む）","正しい","正しい"]},null,8,["contents"]),e(u,{questionNumber:27,title:t,subject:l,questionTitle:"保険料積立金",contents:["正しい","危険保険料 → 貯蓄保険料","正しい"]}),e(u,{questionNumber:28,title:t,subject:l,questionTitle:"事業年度末責任準備金",contents:["正しい","正しい","社員総代会や株主総会 → 取締役会"]}),e(u,{questionNumber:29,title:t,subject:l,questionTitle:"解約返戻金",contents:["正しい","既払込保険料相当額が用いられている → 解約返戻金が用いられている","正しい"]},null,8,["contents"]),e(u,{questionNumber:30,title:t,subject:l,questionTitle:"契約転換制度",contents:["正しい","正しい","一時払保険料に充当 → 分割保険料に充当"]}),e(n,{questionNumber:31,title:t,subject:l,items:[{questionTitle:"契約年齢",content:"正しい"},{questionTitle:"単利",content:"正しい"},{questionTitle:"予定利率",content:"保険金額 → 商品の特性"},{questionTitle:"終価",content:"正しい"},{questionTitle:"保険料の計算原理",content:"自然保険料 → 平準保険料"},{questionTitle:"1年定期保険の純保険料",content:"正しい"},{questionTitle:"責任準備金",content:"正しい"},{questionTitle:"決算による剰余金算定",content:"正しい"},{questionTitle:"変額保険の仕組み",content:"3つ → 2つ（死差益と費差益）"},{questionTitle:"団体定期保険の数理",content:"被保険者ごとに積み上げる → 団体単位で計算<br>死差損団体にも支払われる → 支払われない"},{questionTitle:"死亡率",label:"オ",content:""},{questionTitle:"保険計理の基礎",label:"イ",content:"大数"},{questionTitle:"純保険料の変化",label:"エ",content:"高くなる"},{questionTitle:"責任準備金の積立",label:"ウ",content:"平準保険料"},{questionTitle:"積立に関する法的規制",label:"イ",content:"危険準備金"},{questionTitle:"延長保険",label:"ア",content:"定期保険"},{questionTitle:"配当準備金繰入",label:"オ",content:""},{questionTitle:"剰余金の発生源",label:"エ",content:"価格変動"},{questionTitle:"変額保険の仕組み",label:"ア",content:"死亡保険金額"},{questionTitle:"団体年金制度の財政方式",label:"ア",content:"事前積立"}]})]),e(s,{"previous-route":"keiri2024c","next-route":"keiri2023b"})])]),_:1}))}};export{w as default};
